PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?amendment ?label WHERE {
  ?amendment wdt:P31 wd:Q102410240 ; rdfs:label ?label .
  FILTER(LANG(?label) = "en")
  FILTER NOT EXISTS {
    ?amendment wdt:P921 wd:Q8463
  }
  FILTER NOT EXISTS {
    ?amendment wdt:P921 wd:Q185387
  }
}
ORDER BY ?amendment
